oxy_webhelp_navlinks = {"azr_evaluate_options_cloud_acc_setup-d30753e18192":{"topics":[{"title":"Azure cloud discovery","shortdesc":"<p class=\"shortdesc\">The cloud discovery feature provides a read-only view of Azure resources in <span class=\"ph\">RSC<\/span>. This feature separates workload discovery from workload protection, so         you can view all the resources that exist before choosing what to protect.<\/p>","href":"saas\/azr_cloud_discovery.html","attributes":{"data-id":"azr_cloud_discovery"},"menu":{"hasChildren":false},"tocID":"azr_cloud_discovery-d30753e18206","topics":[]},{"title":"Manual versus OAuth configuration for Azure cloud account","shortdesc":"<p class=\"shortdesc\">A comparative overview of the manual or Configure without OAuth and Configure with         OAuth methods for adding an Azure cloud account to <span class=\"ph\">RSC<\/span>.<\/p>","href":"saas\/azr_manual_vs_oauth_config_cloud_acc.html","attributes":{"data-id":"azr_manual_vs_oauth_config_cloud_acc"},"menu":{"hasChildren":false},"tocID":"azr_manual_vs_oauth_config_cloud_acc-d30753e18220","topics":[]},{"title":"Management group onboarding for Azure subscriptions","shortdesc":"<p class=\"shortdesc\">An overview of how <span class=\"ph\">RSC<\/span> uses Azure management groups to onboard         multiple Azure subscriptions in bulk, including how onboarding works, available methods, and         ongoing permission management.<\/p>","href":"saas\/azr_mgmt_group_onboarding.html","attributes":{"data-id":"azr_mgmt_group_onboarding"},"menu":{"hasChildren":false},"tocID":"azr_mgmt_group_onboarding-d30753e18234","topics":[]},{"title":"Bulk versus individual Azure cloud account addition","shortdesc":"<p class=\"shortdesc\">A comparative overview of bulk and individual addition of Azure cloud accounts,         including management group onboarding.<\/p>","href":"saas\/azr_bulk_vs_indv_cloud_acc_addition.html","attributes":{"data-id":"azr_bulk_vs_indv_cloud_acc_addition"},"menu":{"hasChildren":false},"tocID":"azr_bulk_vs_indv_cloud_acc_addition-d30753e18248","topics":[]},{"title":"Data scanning in Azure","shortdesc":"<p class=\"shortdesc\">When you enable data scanning in an Azure account, <span class=\"ph\">RSC<\/span> scans and         classifies your Azure data based on its sensitivity and also generates intelligent insights         into the data. Data scanning helps you manage cloud posture risks.<\/p>","href":"saas\/azure_data_classification.html","attributes":{"data-id":"azure_data_classification"},"menu":{"hasChildren":false},"tocID":"azure_data_classification-d30753e18259","next":"azure_data_classification-d30753e18259"}]}};